script:
// Client Script for DocType: Vouchers Entry
// الوظيفة: جلب الحساب تلقائياً، حساب الضرائب، وزر GL Ledger مع حل جذري لمشكلة Field not permitted

frappe.ui.form.on('Vouchers Entry', {
    onload: function(frm) {
        // 1. حقن الـ CSS الاحترافي لإخفاء أي رسائل خطأ تقنية متبقية وتجميل الواجهة
        if (!document.getElementById('vouchers-entry-premium-style')) {
            let style = document.createElement('style');
            style.id = 'vouchers-entry-premium-style';
            style.innerHTML = `
                .btn-gl-ledger {
                    background-color: #2c3e50 !important;
                    color: #ecf0f1 !important;
                    font-weight: bold !important;
                    border: 1px solid #34495e !important;
                    box-shadow: 0 2px 5px rgba(0,0,0,0.2) !important;
                }
                .btn-gl-ledger:hover {
                    background-color: #34495e !important;
                    color: #ffffff !important;
                    transform: translateY(-1px);
                }
                .frappe-control[data-fieldname="amount_after_tax"] .control-value {
                    background-color: #e8f5e9;
                    color: #2e7d32;
                    font-weight: bold;
                    border: 1px solid #a5d6a7;
                }
                /* إخفاء نافذة الخطأ الخاصة بالصلاحيات إذا ظهرت */
                .msgprint-dialog .modal-body:contains("Field not permitted") { display: none !important; }
            `;
            document.head.appendChild(style);
        }
        apply_vouchers_filters(frm);
    },

   refresh: function(frm) {
    if (!frm.doc.__islocal && frm.doc.docstatus === 1 && frm.doc.journal_entry) {
        frm.add_custom_button(__('Journal Entry Ledger'), function() {
            // المسار الجديد يوجهك مباشرة إلى مستند القيد اليومي
            let voucher_no = frm.doc.journal_entry || '';
            let url = `/app/journal-entry/${encodeURIComponent(voucher_no)}`;
            
            window.open(url, '_blank');
        }).addClass('btn-gl-ledger');
    }
    apply_vouchers_filters(frm);
},

    payment_type: function(frm) {
        if (frm.doc.references) {
            let p_type = (frm.doc.payment_type === 'Receive') ? '' : '';
            frm.doc.references.forEach(row => {
                if (!row.party_type) {
                    frappe.model.set_value(row.doctype, row.name, 'party_type', p_type);
                }
            });
        }
    }
});

// --- أحداث الجدول الداخلي (references) ---
frappe.ui.form.on('Voucher Entry Account', {
    amount: function(frm, cdt, cdn) {
        compute_tax_for_row_v2(frm, cdt, cdn);
    },
    taxes: function(frm, cdt, cdn) {
        compute_tax_for_row_v2(frm, cdt, cdn);
    },
    party: function(frm, cdt, cdn) {
        // استدعاء الدالة الجديدة لحل مشكلة الحساب
        set_party_account_safely(frm, cdt, cdn);
    },
    references_add: function(frm, cdt, cdn) {
        let p_type = (frm.doc.payment_type === 'Receive') ? '' : '';
        frappe.model.set_value(cdt, cdn, 'party_type', p_type);
    }
});

// ================= الوظائف المساعدة =================

// الحل النهائي: استخدام frappe.call لاستدعاء دالة داخلية تتجاوز قيود الصلاحيات
function set_party_account_safely(frm, cdt, cdn) {
    let row = locals[cdt][cdn];
    
    // شرط: وجود قيمة في حقل party
    if (!row.party || !row.party_type || !frm.doc.company) return;

    frappe.call({
        method: "erpnext.accounts.party.get_party_account", // دالة رسمية في ERPNext
        args: {
            company: frm.doc.company,
            party: row.party,
            party_type: row.party_type
        },
        callback: function(r) {
            if (r.message) {
                // وضع الحساب الناتج مباشرة في حقل account
                frappe.model.set_value(cdt, cdn, 'account', r.message);
            } else {
                // إذا لم يجد حساب خاص، نجرب جلب الحساب الافتراضي للشركة
                fetch_fallback_company_account(frm, cdt, cdn, row.party_type);
            }
        }
    });
}

// دالة احتياطية لجلب حساب الشركة الافتراضي في حال فشل جلب حساب الطرف
function fetch_fallback_company_account(frm, cdt, cdn, party_type) {
    let field = (party_type === 'Customer') ? 'default_receivable_account' : 'default_payable_account';
    
    frappe.call({
        method: "frappe.client.get_value",
        args: {
            doctype: "Company",
            filters: { name: frm.doc.company },
            fieldname: field
        },
        callback: function(r) {
            if (r.message && r.message[field]) {
                frappe.model.set_value(cdt, cdn, 'account', r.message[field]);
            }
        }
    });
}

// حساب الضرائب
function compute_tax_for_row_v2(frm, cdt, cdn) {
    let row = locals[cdt][cdn];
    let amount = flt(row.amount);
    
    if (!row.taxes || amount === 0) {
        frappe.model.set_value(cdt, cdn, 'tax_amount', 0);
        frappe.model.set_value(cdt, cdn, 'amount_before_tax', amount);
        frappe.model.set_value(cdt, cdn, 'amount_after_tax', amount);
        recalc_totals_v2(frm);
        return;
    }

    frappe.db.get_doc('Purchase Taxes and Charges Template', row.taxes).then(doc => {
        let sumRate = 0, included_flag = false;
        if (doc.taxes) {
            doc.taxes.forEach(t => {
                sumRate += flt(t.rate);
                if (t.included_in_print_rate) included_flag = true;
            });
        }
        let tax = 0, before = 0, after = 0;
        if (included_flag) {
            before = flt(amount / (1 + (sumRate / 100)), 2);
            tax = flt(amount - before, 2);
            after = amount;
        } else {
            tax = flt(amount * (sumRate / 100), 2);
            before = amount;
            after = flt(before + tax, 2);
        }
        frappe.model.set_value(cdt, cdn, 'tax_amount', tax);
        frappe.model.set_value(cdt, cdn, 'amount_before_tax', before);
        frappe.model.set_value(cdt, cdn, 'amount_after_tax', after);
        recalc_totals_v2(frm);
    });
}

function recalc_totals_v2(frm) {
    let total_alloc = 0, total_tax = 0;
    (frm.doc.references || []).forEach(r => {
        total_alloc += flt(r.amount_before_tax);
        total_tax += flt(r.tax_amount);
    });
    frm.set_value('total_allocated_amount', flt(total_alloc, 2));
    frm.set_value('total_taxes', flt(total_tax, 2));
    frm.set_value('amount_after_tax', flt(total_alloc + total_tax, 2));
}

function apply_vouchers_filters(frm) {
    frm.set_query('account_payment', () => {
        let m_type = frm.doc.mode_of_payment_type;
        return (m_type === 'Bank' || m_type === 'Cash') ? { filters: { 'account_type': m_type } } : {};
    });
    frm.set_query('party_type', 'references', () => {
        return { filters: [['name', 'in', ['Supplier', 'Customer', 'Employee', 'Shareholder']]] };
    });
}

frappe.ui.form.on("Voucher Entry", {
    mode_of_payment(frm) {
        if (!frm.doc.mode_of_payment) return;

        frappe.db.get_doc("Mode of Payment", frm.doc.mode_of_payment).then(mop => {

            let account_found = null;
            if (mop.accounts && mop.accounts.length > 0) {
                let row = mop.accounts.find(r => r.company === frm.doc.company);
                if (row) account_found = row.account;
            }

            if (account_found && !frm.doc.account_payment) {
                frm.set_value("account_payment", account_found);
            }

            frm.trigger("filter_account_payment");

        });
    },

    mode_of_payment_type(frm) {
        frm.trigger("filter_account_payment");
    },

    refresh(frm) {
        frm.trigger("filter_account_payment");
    },

    filter_account_payment(frm) {

        frm.set_query("account_payment", () => {

            if (frm.doc.mode_of_payment_type === "Bank") {
                return {
                    filters: {
                        account_type: "Bank",
                        company: frm.doc.company
                    }
                }

            } else if (frm.doc.mode_of_payment_type === "Cash") {
                return {
                    filters: {
                        account_type: "Cash",
                        company: frm.doc.company
                    }
                }

            } else {
                return {
                    filters: {
                        company: frm.doc.company
                    }
                }
            }
        })
    }
});

frappe.ui.form.on('Vouchers Entry', {
    refresh: function(frm) {
        // 1. تنسيق الزر CSS بشكل احترافي ملون وحواف ناعمة
        let btn = frm.get_field('get_outstanding_invoices').$wrapper.find('button');
        btn.removeClass('btn-default').addClass('btn-primary');
        btn.css({
            'background': 'linear-gradient(135deg, #6e8efb, #a777e3)',
            'border': 'none',
            'border-radius': '10px',
            'padding': '8px 20px',
            'box-shadow': '0 4px 6px rgba(0,0,0,0.1)',
            'color': '#fff',
            'font-weight': 'bold',
            'transition': '0.3s'
        });

        btn.hover(
            function() { $(this).css({'transform': 'translateY(-2px)', 'box-shadow': '0 6px 12px rgba(0,0,0,0.15)'}); },
            function() { $(this).css({'transform': 'translateY(0)', 'box-shadow': '0 4px 6px rgba(0,0,0,0.1)'}); }
        );
    },

    get_outstanding_invoices: function(frm) {
        // 2. تجميع المبالغ المتاحة لكل عميل ومورد من جدول references
        let customer_funds = {};
        let supplier_funds = {};

        (frm.doc.references || []).forEach(row => {
            if (row.party && row.party_type === 'Customer') {
                customer_funds[row.party] = (customer_funds[row.party] || 0) + (row.amount_before_tax || 0);
            } else if (row.party && row.party_type === 'Supplier') {
                supplier_funds[row.party] = (supplier_funds[row.party] || 0) + (row.amount_before_tax || 0);
            }
        });

        if (Object.keys(customer_funds).length === 0 && Object.keys(supplier_funds).length === 0) {
            frappe.msgprint({
                title: __('Notification'),
                indicator: 'blue',
                message: __('Please add Customers or Suppliers in the "references" table with an amount first.')
            });
            return;
        }

        // 3. تصميم النافذة المنبثقة (Dialog) - إنجليزي وتصميم جانبي
        let d = new frappe.ui.Dialog({
            title: '<span style="color: #6e8efb; font-weight: bold;">🔍 Fetch Outstanding Invoices</span>',
            fields: [
                {
                    label: 'From Date',
                    fieldname: 'from_date',
                    fieldtype: 'Date',
                    reqd: 1,
                    default: frappe.datetime.add_months(frappe.datetime.get_today(), -1),
                    columns: 6 // جعل التاريخين بجوار بعض
                },
                {
                    label: 'To Date',
                    fieldname: 'to_date',
                    fieldtype: 'Date',
                    reqd: 1,
                    default: frappe.datetime.get_today(),
                    columns: 6
                },
                {
                    fieldtype: 'Section Break',
                },
                {
                    label: 'Allocate Payment Amount',
                    fieldname: 'allocate_payment_amount',
                    fieldtype: 'Check',
                    default: 1,
                    description: 'Distribute amounts from references table to invoices'
                }
            ],
            primary_action_label: 'Get Outstanding Invoices',
            primary_action(values) {
                d.hide();
                fetch_and_allocate(frm, values, customer_funds, supplier_funds);
            }
        });

        d.show();
    }
});

async function fetch_and_allocate(frm, values, customer_funds, supplier_funds) {
    // جلب الفواتير الموجودة حالياً لمنع التكرار
    let existing_sales = (frm.doc.vouchers_payment_references || []).map(d => d.reference_name);
    let existing_purchase = (frm.doc.vouchers_payment_references2 || []).map(d => d.reference_name);

    // 4. معالجة العملاء (Customer Table)
    if (Object.keys(customer_funds).length > 0) {
        let sales_invoices = await frappe.db.get_list('Sales Invoice', {
            filters: [
                ['customer', 'in', Object.keys(customer_funds)],
                ['docstatus', '=', 1],
                ['outstanding_amount', '>', 0],
                ['posting_date', 'between', [values.from_date, values.to_date]],
                ['name', 'not in', existing_sales]
            ],
            fields: ['*']
        });

        sales_invoices.forEach(inv => {
            let available = customer_funds[inv.customer] || 0;
            let to_allocate = 0;
            if (values.allocate_payment_amount && available > 0) {
                to_allocate = Math.min(available, inv.outstanding_amount);
                customer_funds[inv.customer] -= to_allocate; // خصم من الرصيد المتاح
            }

            let row = frm.add_child('vouchers_payment_references');
            row.reference_doctype = "Sales Invoice";
            row.reference_name = inv.name;
            row.due_date = inv.due_date;
            row.total_amount = inv.grand_total;
            row.outstanding_amount = inv.outstanding_amount;
            row.allocated_amount = to_allocate;
            row.exchange_rate = inv.conversion_rate || 1;
            row.account = inv.debit_to;
            row.reconcile_effect_on = inv.posting_date;
            row.customer = inv.customer; // جلب العميل للسطر
            row.account_type = 'Receivable';
            row.payment_term = inv.payment_terms_template;
        });
    }

    // 5. معالجة الموردين (Supplier Table 2)
    if (Object.keys(supplier_funds).length > 0) {
        let purchase_invoices = await frappe.db.get_list('Purchase Invoice', {
            filters: [
                ['supplier', 'in', Object.keys(supplier_funds)],
                ['docstatus', '=', 1],
                ['outstanding_amount', '>', 0],
                ['posting_date', 'between', [values.from_date, values.to_date]],
                ['name', 'not in', existing_purchase]
            ],
            fields: ['*']
        });

        purchase_invoices.forEach(inv => {
            let available = supplier_funds[inv.supplier] || 0;
            let to_allocate = 0;
            if (values.allocate_payment_amount && available > 0) {
                to_allocate = Math.min(available, inv.outstanding_amount);
                supplier_funds[inv.supplier] -= to_allocate; // خصم من الرصيد المتاح
            }

            let row = frm.add_child('vouchers_payment_references2');
            row.reference_name = inv.name;
            row.reference_doctype = "Purchase Invoice";
            row.due_date = inv.due_date;
            row.bill_no = inv.bill_no;
            row.total_amount = inv.grand_total;
            row.outstanding_amount = inv.outstanding_amount;
            row.allocated_amount = to_allocate;
            row.exchange_rate = inv.conversion_rate || 1;
            row.account = inv.credit_to;
            row.reconcile_effect_on = inv.posting_date;
            row.suppiler = inv.supplier; // جلب المورد للسطر (بناءً على اسم الحقل المكتوب في طلبك Suppiler)
            row.account_type = 'Payable';
            row.payment_term = inv.payment_terms_template;
        });
    }

    frm.refresh_field('vouchers_payment_references');
    frm.refresh_field('vouchers_payment_references2');
    frappe.show_alert({ message: __('Invoices fetched and allocated smartly!'), indicator: 'green' });
}

frappe.ui.form.on('Journal Entry', {
    refresh: function(frm) {
        // التأكد من وجود قيمة في حقل رقم الشيك/القسيمة قبل إظهار الزر
        if (frm.doc.cheque_no) {
            
            // إضافة الزر في القائمة العلوية
            let btn = frm.add_custom_button(__('Vouchers Entry Ledger'), function() {
                // الانتقال إلى الدوك تايب المستهدف بناءً على الاسم الموجود في cheque_no
                frappe.set_route('Form', 'Vouchers Entry', frm.doc.cheque_no);
            });

            // تطبيق التنسيق الاحترافي (CSS) مباشرة على الزر
            $(btn).addClass('btn-custom-ledger');
            
            // إضافة أيقونة بسيطة للزر لجعله أكثر احترافية
            $(btn).prepend('<i class="fa fa-external-link-alt" style="margin-left: 8px;"></i> ');
        }
    }
});
